// NURS 1000 Exam 4 — Mobility & Assistive Devices (120 Questions)
const S={MO:"Mobility & Body Mechanics",CR:"Crutches, Canes & Walkers"};
const R=[
// ===== GENERAL KNOWLEDGE (Q1-30) =====
{id:1,s:"MO",t:"mc",q:"Which mnemonic represents the four properties of muscle tissue?",o:["CEEE — Contractibility, Excitability, Extensibility, Elasticity","CEES — Contractibility, Excitability, Extensibility, Stability","CCEE — Contractibility, Conductivity, Extensibility, Elasticity","CEEP — Contractibility, Excitability, Extensibility, Plasticity"],c:[0],e:"The four muscle properties are remembered by CEEE: Contractibility (ability to shorten), Excitability (respond to stimuli), Extensibility (ability to stretch), and Elasticity (return to original shape). CEES, CCEE, and CEEP substitute incorrect terms — Stability, Conductivity, and Plasticity are not among the four muscle properties.",a:"A) CEEE — Contractibility, Excitability, Extensibility, Elasticity",r:"Muscle Properties"},
{id:2,s:"MO",t:"mc",q:"How many muscles are in the human body, and approximately what percentage of body weight do they account for?",o:["200 muscles; 25% of body weight","400 muscles; 35% of body weight","600+ muscles; about 50% of body weight","800 muscles; about 60% of body weight"],c:[2],e:"The human body has more than 600 muscles, which account for approximately half (50%) of total body weight. The other options cite incorrect numbers. Knowing this helps appreciate the metabolic and functional significance of the muscular system.",a:"C) 600+ muscles; about 50% of body weight",r:"Musculoskeletal Overview"},
{id:3,s:"MO",t:"mc",q:"Which type of muscle is voluntary and attached to bones by tendons?",o:["Cardiac muscle","Smooth muscle","Skeletal muscle","Visceral muscle"],c:[2],e:"Skeletal muscle is the only voluntary muscle type and is attached to bones via tendons, enabling movement. Cardiac muscle is involuntary and found only in the heart. Smooth (visceral) muscle is involuntary and lines blood vessels and organs. 'Visceral muscle' is another name for smooth muscle.",a:"C) Skeletal muscle",r:"Muscle Types"},
{id:4,s:"MO",t:"mc",q:"Cardiac muscle is classified as which type of control?",o:["Voluntary","Involuntary","Both voluntary and involuntary","Neither voluntary nor involuntary"],c:[1],e:"Cardiac muscle is involuntary — it contracts automatically without conscious control, regulated by the heart's intrinsic conduction system. It is not under voluntary control. The options 'both' and 'neither' are incorrect because cardiac muscle is definitively involuntary.",a:"B) Involuntary",r:"Muscle Types"},
{id:5,s:"MO",t:"mc",q:"How many bones are in the adult human body?",o:["106","186","206","306"],c:[2],e:"The adult human skeleton contains 206 bones. This is a key fact in musculoskeletal anatomy. The other numbers (106, 186, 306) are incorrect distractors. Infants have more bones (~270) that fuse over time to reach 206 in adulthood.",a:"C) 206",r:"Skeletal System"},
{id:6,s:"MO",t:"mc",q:"Which bone type is primarily responsible for weight bearing?",o:["Short bones","Flat bones","Long bones","Sesamoid bones"],c:[2],e:"Long bones (such as the femur and tibia) are the primary weight-bearing bones of the body. Short bones are found in the wrist and ankle and provide stability. Flat bones (skull, ribs) protect organs. Sesamoid bones (like the patella) are embedded in tendons and protect them from wear.",a:"C) Long bones",r:"Bone Types"},
{id:7,s:"MO",t:"mc",q:"The patella is classified as which type of bone?",o:["Long bone","Short bone","Flat bone","Sesamoid bone"],c:[3],e:"The patella (kneecap) is the largest sesamoid bone in the body — it is embedded within the quadriceps tendon. It is not a long bone (those are weight-bearing limb bones), short bone (wrist/ankle), or flat bone (skull/ribs).",a:"D) Sesamoid bone",r:"Bone Types"},
{id:8,s:"MO",t:"mc",q:"Short bones are found primarily in which areas of the body?",o:["Skull and ribs","Upper arm and thigh","Wrist and ankle","Face and vertebrae"],c:[2],e:"Short bones are roughly cube-shaped and found in the wrist (carpals) and ankle (tarsals), where they provide stability and some movement. The skull and ribs contain flat bones. The upper arm and thigh contain long bones. The face and vertebrae contain irregular bones.",a:"C) Wrist and ankle",r:"Bone Types"},
{id:9,s:"MO",t:"mc",q:"Which joint movement involves turning the palm downward?",o:["Supination","Pronation","Inversion","Eversion"],c:[1],e:"Pronation is turning the forearm so the palm faces downward. Supination is the opposite — turning the palm upward (think: 'soup in your hand'). Inversion turns the sole of the foot inward, and eversion turns it outward — both are foot movements, not forearm.",a:"B) Pronation",r:"Joint Movements"},
{id:10,s:"MO",t:"mc",q:"Moving a limb away from the midline of the body is called:",o:["Adduction","Abduction","Flexion","Extension"],c:[1],e:"Abduction moves a limb away from the body's midline (think: 'abduct' = take away). Adduction moves toward the midline. Flexion decreases the angle at a joint, and extension increases it. These are fundamental ROM terminology.",a:"B) Abduction",r:"Joint Movements"},
{id:11,s:"MO",t:"mc",q:"Dorsiflexion of the foot involves:",o:["Pointing the toes downward","Pulling the toes upward toward the shin","Turning the sole of the foot inward","Turning the sole of the foot outward"],c:[1],e:"Dorsiflexion pulls the top (dorsum) of the foot upward toward the shin. Pointing the toes downward is plantarflexion. Turning the sole inward is inversion, and turning it outward is eversion. Dorsiflexion is assessed in neurovascular checks.",a:"B) Pulling the toes upward toward the shin",r:"Joint Movements"},
{id:12,s:"MO",t:"mc",q:"An exaggerated inward curvature of the lower back is called:",o:["Kyphosis","Scoliosis","Lordosis","Flat back"],c:[2],e:"Lordosis is an exaggerated inward (anterior) curvature of the lumbar spine (lower back). Kyphosis is an exaggerated outward curvature of the thoracic spine (upper back rounding). Scoliosis is a lateral C- or S-shaped curvature. Flat back is loss of the normal lumbar curve.",a:"C) Lordosis",r:"Postural Misalignments"},
{id:13,s:"MO",t:"mc",q:"An exaggerated rounding of the upper back (thoracic spine) is called:",o:["Lordosis","Kyphosis","Scoliosis","Sway back"],c:[1],e:"Kyphosis is an excessive outward curvature of the thoracic spine, creating a 'hunchback' appearance. Lordosis affects the lumbar spine. Scoliosis is lateral curvature. Sway back involves forward displacement of the hips with backward lean of the trunk.",a:"B) Kyphosis",r:"Postural Misalignments"},
{id:14,s:"MO",t:"mc",q:"Scoliosis is best described as:",o:["Exaggerated lumbar curve","Exaggerated thoracic curve","Lateral C-shaped or S-shaped curvature of the spine","Loss of all spinal curves"],c:[2],e:"Scoliosis is a lateral (side-to-side) curvature of the spine that can form a C or S shape. It is not an anterior-posterior curve like lordosis (lumbar) or kyphosis (thoracic). Loss of all spinal curves describes flat back syndrome.",a:"C) Lateral C-shaped or S-shaped curvature of the spine",r:"Postural Misalignments"},
{id:15,s:"MO",t:"mc",q:"How often should an immobilized patient be repositioned at minimum?",o:["Every 30 minutes","Every 1 hour","Every 2 hours","Every 4 hours"],c:[2],e:"The standard of care is to reposition immobile patients at least every 2 hours to prevent pressure ulcers. Every 30 minutes or 1 hour may be used in high-risk patients but is not the minimum standard. Every 4 hours is too infrequent and increases risk of skin breakdown.",a:"C) Every 2 hours",r:"Immobility Interventions"},
{id:16,s:"MO",t:"mc",q:"Which respiratory complication is most associated with immobility?",o:["Pneumothorax","Atelectasis","Pulmonary embolism","Asthma exacerbation"],c:[1],e:"Atelectasis (collapse of alveoli) is the most direct respiratory complication of immobility due to shallow breathing and mucus pooling. Pulmonary embolism is a cardiovascular complication (from DVT). Pneumothorax and asthma exacerbation are not typical immobility complications.",a:"B) Atelectasis",r:"Immobility Complications"},
{id:17,s:"MO",t:"mc",q:"Which cardiovascular complication is a major concern for immobilized patients?",o:["Hypertension","Atrial fibrillation","Deep vein thrombosis (DVT)","Aortic aneurysm"],c:[2],e:"DVT (deep vein thrombosis) is a major cardiovascular risk of immobility due to venous stasis — blood pools in the legs when there is no muscle contraction to aid venous return. Hypertension, atrial fibrillation, and aortic aneurysm are not directly caused by immobility.",a:"C) Deep vein thrombosis (DVT)",r:"Immobility Complications"},
{id:18,s:"MO",t:"mc",q:"What is the purpose of antiembolic (TED) stockings?",o:["Prevent skin breakdown on the legs","Promote DVT prevention by compressing veins and improving venous return","Keep the patient's legs warm","Reduce edema from heart failure"],c:[1],e:"Antiembolic stockings apply graduated compression to the legs to promote venous return and prevent DVT/venous stasis. They are not primarily for skin breakdown prevention, warmth, or heart failure edema — though compression may have secondary benefits, DVT prevention is the primary purpose.",a:"B) Promote DVT prevention by compressing veins and improving venous return",r:"Immobility Interventions"},
{id:19,s:"MO",t:"mc",q:"ADLs stands for:",o:["Active Daily Limitations","Activities of Daily Living","Assisted Device Logistics","Ambulatory Daily Lifting"],c:[1],e:"ADLs stands for Activities of Daily Living — the basic self-care tasks a person performs daily such as bathing, dressing, eating, toileting, and mobility. The other options are fabricated terms that do not exist in nursing terminology.",a:"B) Activities of Daily Living",r:"Mobility Terminology"},
{id:20,s:"MO",t:"mc",q:"Which device helps prevent atelectasis in immobilized patients?",o:["Sequential compression device","Incentive spirometer","Antiembolic stockings","Trapeze bar"],c:[1],e:"An incentive spirometer encourages deep breathing and sustained maximal inspiration, helping to prevent and treat atelectasis. SCDs and antiembolic stockings prevent DVT, not atelectasis. A trapeze bar assists with repositioning but does not directly address respiratory function.",a:"B) Incentive spirometer",r:"Immobility Interventions"},
{id:21,s:"MO",t:"tf",q:"True or False: Smooth muscle is found lining blood vessels and organs and is under voluntary control.",o:["True","False"],c:[1],e:"This statement is FALSE. Smooth muscle does line blood vessels and organs, but it is under involuntary (autonomic) control, not voluntary. Only skeletal muscle is voluntarily controlled. This is a key distinction among the three muscle types.",a:"B) False",r:"Muscle Types"},
{id:22,s:"MO",t:"tf",q:"True or False: The human body has 206 bones in adulthood.",o:["True","False"],c:[0],e:"This statement is TRUE. The adult human body contains 206 bones. Infants are born with approximately 270 bones, many of which fuse together during growth and development to reach the adult count of 206.",a:"A) True",r:"Skeletal System"},
{id:23,s:"MO",t:"tf",q:"True or False: Immobility affects only the musculoskeletal system.",o:["True","False"],c:[1],e:"This is FALSE. Immobility affects ALL body systems — respiratory (atelectasis), cardiovascular (DVT), musculoskeletal (contractures, muscle atrophy), integumentary (pressure ulcers), gastrointestinal (constipation), urinary (stasis, UTI), and metabolic systems.",a:"B) False",r:"Immobility Complications"},
{id:24,s:"MO",t:"tf",q:"True or False: Contractures are a musculoskeletal complication of prolonged immobility.",o:["True","False"],c:[0],e:"This is TRUE. Contractures — permanent shortening of muscles, tendons, and ligaments — develop when joints are not moved through their full ROM regularly. They are a direct musculoskeletal complication of immobility and can be prevented with ROM exercises.",a:"A) True",r:"Immobility Complications"},
{id:25,s:"MO",t:"fib",q:"The mnemonic for the four muscle properties is ____.",o:[],c:["CEEE"],e:"CEEE stands for Contractibility, Excitability, Extensibility, and Elasticity — the four fundamental properties of all muscle tissue. This mnemonic helps students quickly recall these properties on exams.",a:"CEEE",r:"Muscle Properties"},
{id:26,s:"MO",t:"fib",q:"Patients should use the incentive spirometer every ____ to ____ hours to prevent atelectasis.",o:[],c:["1","2"],e:"Incentive spirometry, deep breathing, and coughing exercises should be performed every 1 to 2 hours for immobilized patients to prevent atelectasis. This frequency maintains alveolar inflation and promotes airway clearance.",a:"1 to 2",r:"Immobility Interventions"},
{id:27,s:"MO",t:"mc",q:"The mnemonic 'MCP GM' stands for:",o:["Muscles Contract and Pull to Generate Movement","Motor Cortex Produces Gross Movement","Muscular Coordination Promotes Good Mechanics","Mechanical Compression Prevents Gait Malfunction"],c:[0],e:"MCP GM = Muscles Contract and Pull to Generate Movement. This mnemonic summarizes the basic mechanism of the musculoskeletal system — muscles shorten (contract) and pull on bones via tendons to produce movement. The other options are fabricated.",a:"A) Muscles Contract and Pull to Generate Movement",r:"Muscle Properties"},
{id:28,s:"MO",t:"mc",q:"Irregular bones are found in which areas of the body?",o:["Wrist and ankle","Skull and ribs","Face and vertebrae","Upper and lower extremities"],c:[2],e:"Irregular bones have complex shapes and are found in the face (such as the mandible) and vertebral column. Wrist and ankle contain short bones. Skull and ribs contain flat bones. Upper and lower extremities primarily contain long bones.",a:"C) Face and vertebrae",r:"Bone Types"},
{id:29,s:"MO",t:"mc",q:"Which joint movement describes a circular motion that combines flexion, extension, abduction, and adduction?",o:["Rotation","Circumduction","Pronation","Supination"],c:[1],e:"Circumduction is a cone-shaped circular movement combining flexion, extension, abduction, and adduction — such as winding up to throw a ball. Rotation is turning around an axis. Pronation and supination are forearm movements only.",a:"B) Circumduction",r:"Joint Movements"},
{id:30,s:"MO",t:"mc",q:"Turning the sole of the foot inward is called:",o:["Eversion","Inversion","Dorsiflexion","Plantarflexion"],c:[1],e:"Inversion turns the sole of the foot inward (medially). Eversion turns it outward (laterally). Dorsiflexion pulls the foot upward, and plantarflexion points it downward. These are specific foot/ankle movements.",a:"B) Inversion",r:"Joint Movements"},

// ===== TRIAGE (Q31-60) =====
{id:31,s:"MO",t:"mc",q:"A nurse is triaging four patients. Which patient should be assessed FIRST?",o:["A patient who has not been repositioned in 3 hours","A patient reporting sudden calf pain and swelling in one leg","A patient requesting help with ROM exercises","A patient needing assistance getting out of bed"],c:[1],e:"Sudden unilateral calf pain and swelling suggests DVT — a potentially life-threatening complication if the clot dislodges and becomes a pulmonary embolism. This requires immediate assessment. Delayed repositioning, ROM exercises, and ambulation assistance are important but not emergencies.",a:"B) A patient reporting sudden calf pain and swelling in one leg",r:"Triage — DVT"},
{id:32,s:"MO",t:"mc",q:"Which patient requires the MOST urgent nursing intervention?",o:["An immobile patient who has not used the incentive spirometer in 4 hours","A patient with new-onset dyspnea, tachycardia, and chest pain after hip surgery","A patient requesting a walker to ambulate to the bathroom","A patient with a stage 1 pressure ulcer on the sacrum"],c:[1],e:"Sudden dyspnea, tachycardia, and chest pain post-surgery suggest pulmonary embolism — a life-threatening emergency. The other situations (missed spirometry, walker request, stage 1 pressure ulcer) require attention but are not immediately life-threatening.",a:"B) A patient with new-onset dyspnea, tachycardia, and chest pain after hip surgery",r:"Triage — Pulmonary Embolism"},
{id:33,s:"MO",t:"mc",q:"A nurse receives report on four patients. Which requires PRIORITY assessment?",o:["A patient ambulating independently with a walker","A post-stroke patient who fell while attempting to transfer without assistance","A patient requesting a cane to walk in the hallway","A patient doing active ROM exercises in bed"],c:[1],e:"A fall requires immediate assessment for injury — especially in a post-stroke patient who may have altered sensation or be on anticoagulants. The other patients are functioning safely and do not need urgent intervention.",a:"B) A post-stroke patient who fell while attempting to transfer without assistance",r:"Triage — Falls"},
{id:34,s:"MO",t:"mc",q:"Which immobilized patient finding requires the nurse to intervene FIRST?",o:["Patient reports boredom and requests a television","Patient has absent pedal pulses bilaterally","Patient requests assistance to reposition in bed","Patient has a slightly reddened area on the coccyx that blanches with pressure"],c:[1],e:"Absent pedal pulses bilaterally indicate severely compromised circulation — this could signify arterial occlusion or DVT with vascular compromise and requires immediate intervention. Boredom, repositioning, and a blanchable red area are lower priority.",a:"B) Patient has absent pedal pulses bilaterally",r:"Triage — Circulation"},
{id:35,s:"MO",t:"mc",q:"A nurse is triaging calls. Which patient concern is MOST urgent?",o:["'I haven't had a bowel movement in 2 days since being on bed rest'","'My right leg is swollen and painful, and the skin feels warm'","'I need help doing my leg exercises'","'I want to know when I can start walking again'"],c:[1],e:"A swollen, painful, warm leg is classic for DVT, which can progress to pulmonary embolism if untreated. Constipation from immobility, exercise assistance, and ambulation questions are important but not urgent or life-threatening.",a:"B) 'My right leg is swollen and painful, and the skin feels warm'",r:"Triage — DVT"},
{id:36,s:"CR",t:"mc",q:"A nurse observes a patient using crutches. Which finding requires IMMEDIATE intervention?",o:["The patient is using a 4-point gait pattern","The crutch tips are 6 inches in front and to the side","The patient is resting body weight on the axillary pads","There are 2 finger widths between the axilla and the crutch pad"],c:[2],e:"Resting weight on the axillary pads causes brachial plexus nerve damage (crutch palsy) — remember 'No weight on pits!' The other options describe correct crutch use: 4-point gait is appropriate, 6 inches is the correct tripod position, and 2-3 finger widths is proper fitting.",a:"C) The patient is resting body weight on the axillary pads",r:"Triage — Crutch Safety"},
{id:37,s:"CR",t:"mc",q:"Which patient using a cane needs IMMEDIATE correction?",o:["A patient holding the cane on the same side as the weak leg","A patient advancing the cane and weak leg together","A patient with the cane handle at wrist height","A patient stepping with the strong leg after the cane and weak leg"],c:[0],e:"The cane must be held on the OPPOSITE side of the weak leg — 'Cane on the GOOD side, step with the BAD side.' Holding it on the same side provides no mechanical advantage. The other options describe correct cane use technique.",a:"A) A patient holding the cane on the same side as the weak leg",r:"Triage — Cane Safety"},
{id:38,s:"MO",t:"mc",q:"A nurse is assessing four immobilized patients. Which finding is MOST concerning?",o:["Decreased appetite","Non-blanchable redness over the sacrum","Mild constipation","Decreased muscle tone in the legs"],c:[1],e:"Non-blanchable redness indicates tissue damage has begun (Stage 1 pressure ulcer) and requires immediate intervention to prevent progression. Decreased appetite, mild constipation, and decreased muscle tone are expected immobility effects but are not as immediately concerning.",a:"B) Non-blanchable redness over the sacrum",r:"Triage — Pressure Ulcers"},
{id:39,s:"MO",t:"mc",q:"Which patient should the nurse see FIRST after receiving shift report?",o:["A patient who needs daily ROM exercises performed","A patient with new-onset confusion and oxygen saturation of 88%","A patient requesting pain medication before ambulation","A patient who needs antiembolic stockings applied"],c:[1],e:"New-onset confusion with SpO2 of 88% indicates hypoxemia — possibly from atelectasis or pulmonary embolism — and requires immediate assessment and oxygen therapy. ROM exercises, pain medication, and stocking application are scheduled tasks that can wait.",a:"B) A patient with new-onset confusion and oxygen saturation of 88%",r:"Triage — Respiratory"},
{id:40,s:"CR",t:"mc",q:"A nurse sees a patient on crutches attempting to go down stairs by leading with the strong leg. What should the nurse do FIRST?",o:["Praise the patient for attempting stairs independently","Stop the patient and correct the technique","Call the physical therapist immediately","Document the observation and continue monitoring"],c:[1],e:"When going downstairs on crutches, the crutches and weak leg go FIRST, then the strong leg follows ('down with the bad'). Leading with the strong leg is dangerous and could cause a fall. The nurse must stop and correct this immediately. Documentation can follow.",a:"B) Stop the patient and correct the technique",r:"Triage — Crutch Safety"},
{id:41,s:"MO",t:"mc",q:"A nurse is triaging four immobile patients. Which assessment finding requires the MOST urgent intervention?",o:["Patient A: Has not ambulated in 12 hours post-surgery","Patient B: Complains of sudden shortness of breath and pleuritic chest pain","Patient C: Has a blanchable reddened area on the heel","Patient D: Reports feeling stiff after lying in bed all day"],c:[1],e:"Sudden shortness of breath with pleuritic chest pain in an immobile patient strongly suggests pulmonary embolism, a life-threatening emergency. The other findings (delayed ambulation, blanchable redness, stiffness) require attention but are not immediately life-threatening.",a:"B) Patient B: Complains of sudden shortness of breath and pleuritic chest pain",r:"Triage — Pulmonary Embolism"},
{id:42,s:"MO",t:"mc",q:"Which newly immobilized patient is at HIGHEST risk for skin breakdown?",o:["A 25-year-old with a broken wrist in a cast","A 78-year-old with diabetes and decreased sensation who is bedbound","A 30-year-old on bed rest for 24 hours after a concussion","A 40-year-old who is non-weight-bearing on the left leg but mobile with crutches"],c:[1],e:"The elderly, diabetic, bedbound patient with decreased sensation has the highest risk — advanced age, diabetes (impairs circulation and healing), decreased sensation (cannot feel pressure), and complete immobility are all major risk factors. The other patients have fewer risk factors.",a:"B) A 78-year-old with diabetes and decreased sensation who is bedbound",r:"Triage — Pressure Ulcer Risk"},
{id:43,s:"CR",t:"mc",q:"A patient with a right fractured ankle is using a 3-point gait. The nurse observes the patient bearing weight on the right foot. What is the PRIORITY action?",o:["Encourage the patient to continue as tolerated","Immediately instruct the patient to stop bearing weight on the right foot","Apply an ice pack to the right ankle","Document the patient's progress"],c:[1],e:"A 3-point gait is used for non-weight-bearing injuries — ALL weight goes on the unaffected foot and both crutches. Bearing weight on the fractured ankle could worsen the fracture. The nurse must immediately correct this technique. Ice and documentation are not the priority.",a:"B) Immediately instruct the patient to stop bearing weight on the right foot",r:"Triage — Crutch Gait"},
{id:44,s:"MO",t:"mc",q:"A nurse finds an immobilized patient with a positive Homans' sign (calf pain on dorsiflexion). The priority action is to:",o:["Apply a warm compress and elevate the leg","Massage the affected calf vigorously","Notify the healthcare provider immediately and avoid manipulating the leg","Encourage the patient to ambulate immediately"],c:[2],e:"A positive Homans' sign may indicate DVT. The nurse should NOT massage the leg (could dislodge a clot), NOT ambulate the patient, and NOT apply heat without an order. The priority is to notify the provider immediately and avoid manipulating the limb until DVT is ruled out.",a:"C) Notify the healthcare provider immediately and avoid manipulating the leg",r:"Triage — DVT"},
{id:45,s:"MO",t:"sata",q:"Which findings in an immobilized patient indicate possible deep vein thrombosis (DVT)? Select all that apply.",o:["Unilateral leg swelling","Warmth and redness over the calf","Positive Homans' sign","Bilateral pedal edema"],c:[0,1,2],e:"DVT typically presents with unilateral leg swelling, warmth, redness, and pain — often with a positive Homans' sign. Bilateral pedal edema is more suggestive of heart failure or fluid overload rather than DVT, which characteristically affects one limb.",a:"A, B, C) Unilateral leg swelling; Warmth and redness over the calf; Positive Homans' sign",r:"Triage — DVT Assessment"},
{id:46,s:"MO",t:"mc",q:"A nurse is triaging. Which immobilized patient requires assessment FIRST?",o:["A patient who reports 'pins and needles' in both feet after lying flat for 6 hours","A patient whose urine output has been 100 mL in the last 8 hours","A patient with mild muscle atrophy noted in the thighs","A patient requesting a bedpan"],c:[1],e:"Urine output of 100 mL in 8 hours (12.5 mL/hr) indicates oliguria — possible renal complications from immobility or dehydration requiring urgent evaluation. Paresthesias may resolve with repositioning, muscle atrophy is expected, and a bedpan request is routine.",a:"B) A patient whose urine output has been 100 mL in the last 8 hours",r:"Triage — Urinary Complications"},
{id:47,s:"CR",t:"mc",q:"Which observation of a patient using a walker requires the nurse to intervene?",o:["The patient stands in the middle of the walker","The patient moves the walker forward about 12 inches","The patient steps with the strong leg first, then the weak leg","The patient uses a firm grip on the walker handles"],c:[2],e:"With a walker, the patient should step with the WEAK leg first (into the support of the walker), then follow with the strong leg. Stepping with the strong leg first leaves the weak leg unsupported. Standing in the middle, moving forward 12 inches, and firm grip are correct technique.",a:"C) The patient steps with the strong leg first, then the weak leg",r:"Triage — Walker Safety"},
{id:48,s:"MO",t:"mc",q:"A patient on bed rest reports difficulty breathing when lying flat. The nurse should FIRST:",o:["Elevate the head of the bed and assess respiratory status","Administer a bronchodilator","Call a rapid response team","Document the finding and continue rounds"],c:[0],e:"Elevating the head of bed (semi-Fowler's or high-Fowler's) improves lung expansion and is the immediate first action. A bronchodilator requires an order. Calling a rapid response may be needed but assessment comes first. Simply documenting without acting is inappropriate for a new symptom.",a:"A) Elevate the head of the bed and assess respiratory status",r:"Triage — Respiratory"},
{id:49,s:"MO",t:"sata",q:"Which body systems are affected by immobility? Select all that apply.",o:["Respiratory","Cardiovascular","Musculoskeletal","Integumentary","All body systems are affected"],c:[4],e:"Immobility affects ALL body systems — respiratory (atelectasis), cardiovascular (DVT), musculoskeletal (contractures, atrophy), integumentary (pressure ulcers), GI (constipation), urinary (stasis, UTIs), and metabolic (negative nitrogen balance). The best answer is 'All body systems.'",a:"E) All body systems are affected",r:"Immobility Complications"},
{id:50,s:"MO",t:"mc",q:"The nurse finds a bed-bound patient with crackles in the lung bases bilaterally. This finding is MOST likely related to:",o:["Fluid overload from IV therapy","Hypostatic pneumonia from immobility","An allergic reaction","Asthma exacerbation"],c:[1],e:"Bilateral basilar crackles in an immobile patient suggest hypostatic pneumonia — fluid and secretions pool in the dependent lung areas due to lack of position changes and shallow breathing. Fluid overload is possible but immobility is the most likely cause in this context.",a:"B) Hypostatic pneumonia from immobility",r:"Triage — Respiratory Complications"},
{id:51,s:"CR",t:"mc",q:"A patient using crutches reports tingling and numbness in their hands. The FIRST nursing action is:",o:["Tell the patient this is normal","Assess how the patient is using the crutches and check for axillary pressure","Remove the crutches permanently","Apply wrist splints"],c:[1],e:"Tingling and numbness suggest nerve compression — likely from bearing weight on the axillae or improper hand grip. The nurse should first assess crutch technique. This is not normal, removing crutches isn't the answer, and wrist splints don't address the cause.",a:"B) Assess how the patient is using the crutches and check for axillary pressure",r:"Triage — Crutch Nerve Damage"},
{id:52,s:"MO",t:"mc",q:"A nurse reviews labs for an immobilized patient. Which finding is MOST concerning?",o:["Serum calcium 8.8 mg/dL","Serum calcium 12.5 mg/dL","Hemoglobin 13 g/dL","BUN 15 mg/dL"],c:[1],e:"Serum calcium of 12.5 mg/dL indicates hypercalcemia — a metabolic complication of immobility as calcium leaches from unstressed bones. Normal calcium is 8.5–10.5 mg/dL. The other lab values are within normal limits.",a:"B) Serum calcium 12.5 mg/dL",r:"Triage — Metabolic Complications"},
{id:53,s:"MO",t:"mc",q:"A patient who has been immobile for 5 days attempts to stand and becomes dizzy and lightheaded. The nurse recognizes this as:",o:["A normal response to activity","Orthostatic hypotension","A sign of inner ear infection","Hypoglycemia"],c:[1],e:"Orthostatic hypotension is a common cardiovascular effect of prolonged immobility — the body loses its ability to compensate for position changes. The nurse should help the patient sit down, dangle legs, and progress slowly. It is not 'normal,' nor is it likely an ear infection or hypoglycemia.",a:"B) Orthostatic hypotension",r:"Triage — Cardiovascular"},
{id:54,s:"MO",t:"tf",q:"True or False: Massaging a reddened area over a bony prominence helps prevent pressure ulcers.",o:["True","False"],c:[1],e:"This is FALSE. Massaging reddened areas over bony prominences is contraindicated — it can cause further tissue damage by increasing pressure on already-compromised capillaries. Instead, relieve pressure by repositioning and protecting the area.",a:"B) False",r:"Triage — Pressure Ulcers"},
{id:55,s:"MO",t:"mc",q:"A nurse is caring for four patients. Which one needs to be seen FIRST?",o:["A patient requesting help to ambulate with their new walker","A patient with bilateral leg weakness who attempted to stand alone and is now on the floor","A patient who is due for ROM exercises","A patient asking about discharge instructions regarding crutch use"],c:[1],e:"A patient who has fallen is the priority — immediate assessment for injury is required, especially with pre-existing bilateral weakness. Walker assistance, ROM exercises, and discharge teaching can be scheduled after ensuring patient safety.",a:"B) A patient with bilateral leg weakness who attempted to stand alone and is now on the floor",r:"Triage — Falls"},
{id:56,s:"MO",t:"mc",q:"An immobilized patient has not had a bowel movement in 4 days. The nurse recognizes this is caused by:",o:["Increased peristalsis from bed rest","Decreased peristalsis and reduced GI motility from immobility","An intestinal obstruction requiring surgery","A food allergy"],c:[1],e:"Immobility decreases peristalsis and GI motility, commonly causing constipation. This is a known GI complication of bed rest. It is not caused by increased peristalsis, and while obstruction is possible, immobility-related constipation is far more likely in this context.",a:"B) Decreased peristalsis and reduced GI motility from immobility",r:"Triage — GI Complications"},
{id:57,s:"CR",t:"mc",q:"A patient with a left leg fracture is being fitted for crutches. The nurse notes the crutch pad is pressing firmly into the axilla with no gap. What is the PRIORITY action?",o:["Document that the crutches fit properly","Adjust the crutches so there are 2-3 finger widths between the axilla and the crutch pad","Add extra padding to the axillary pad","Tell the patient to use a walker instead"],c:[1],e:"Proper crutch fitting requires 2-3 finger widths (about 1-2 inches) between the axilla and the crutch pad to prevent nerve damage. No gap means the crutches are too tall. Extra padding alone won't fix the height issue. The nurse must adjust the crutch height immediately.",a:"B) Adjust the crutches so there are 2-3 finger widths between the axilla and the crutch pad",r:"Triage — Crutch Fitting"},
{id:58,s:"MO",t:"sata",q:"Which interventions help prevent respiratory complications of immobility? Select all that apply.",o:["Incentive spirometry every 1-2 hours","Deep breathing and coughing exercises","Repositioning at least every 2 hours","Applying antiembolic stockings"],c:[0,1,2],e:"Incentive spirometry, deep breathing/coughing, and repositioning all help maintain lung expansion and airway clearance to prevent atelectasis and pneumonia. Antiembolic stockings prevent DVT (a cardiovascular complication), not respiratory complications.",a:"A, B, C) Incentive spirometry; Deep breathing and coughing; Repositioning",r:"Triage — Respiratory Interventions"},
{id:59,s:"MO",t:"mc",q:"A nurse assesses a patient who has been on bed rest for 1 week. Which finding requires IMMEDIATE reporting to the healthcare provider?",o:["Muscle weakness in the lower extremities","A 5 cm x 5 cm area of deep tissue injury on the sacrum","Mild joint stiffness","Decreased appetite"],c:[1],e:"Deep tissue injury (DTI) on the sacrum is a serious pressure ulcer finding that can indicate extensive underlying tissue damage and requires immediate provider notification. Muscle weakness, joint stiffness, and decreased appetite are expected immobility effects that can be managed with nursing interventions.",a:"B) A 5 cm x 5 cm area of deep tissue injury on the sacrum",r:"Triage — Pressure Ulcers"},
{id:60,s:"MO",t:"mc",q:"An immobilized patient develops a urinary tract infection. The nurse understands this is MOST likely caused by:",o:["Excessive fluid intake","Urinary stasis from immobility","Use of an incentive spirometer","Frequent repositioning"],c:[1],e:"Urinary stasis from immobility allows bacteria to multiply in stagnant urine, increasing UTI risk. Excessive fluid intake actually helps prevent UTIs. Incentive spirometry and repositioning address respiratory and skin complications, not urinary ones.",a:"B) Urinary stasis from immobility",r:"Triage — Urinary Complications"},

// ===== PRIORITIZING (Q61-90) =====
{id:61,s:"MO",t:"mc",q:"A nurse has four tasks to complete. Which should be done FIRST?",o:["Perform passive ROM exercises on a paralyzed patient","Apply SCDs to a post-operative patient who just returned from surgery","Assist a stable patient with morning ambulation","Document yesterday's intake and output"],c:[1],e:"Applying SCDs to a fresh post-op patient is the priority because the risk of DVT is highest immediately after surgery and during initial immobility. ROM exercises, ambulation, and documentation are important but can be done after DVT prevention measures are in place.",a:"B) Apply SCDs to a post-operative patient who just returned from surgery",r:"Prioritizing — DVT Prevention"},
{id:62,s:"MO",t:"mc",q:"The nurse is planning care for an immobilized patient. Which intervention takes HIGHEST priority?",o:["Arranging for a dietary consult for increased fiber","Performing a skin assessment and repositioning the patient","Setting up a television for the patient","Teaching the family about discharge planning"],c:[1],e:"Skin assessment and repositioning directly prevent pressure ulcers, which can develop in as little as 2 hours of unrelieved pressure. Dietary consult, entertainment, and discharge teaching are important but do not address the immediate risk of tissue injury.",a:"B) Performing a skin assessment and repositioning the patient",r:"Prioritizing — Skin Integrity"},
{id:63,s:"CR",t:"mc",q:"A nurse is teaching three patients about assistive devices. Which patient should be taught FIRST?",o:["A patient being discharged in 3 days who will need a walker","A patient being discharged today who will go home on crutches","A patient who will begin cane training next week"],c:[1],e:"The patient being discharged TODAY with crutches has the most immediate need for education — they must be safe with the device before leaving. The walker patient has 3 more days, and the cane patient has a week. Prioritize by urgency of need.",a:"B) A patient being discharged today who will go home on crutches",r:"Prioritizing — Patient Education"},
{id:64,s:"MO",t:"mc",q:"A nurse is caring for a patient 2 days post-hip replacement. Which activity should be prioritized?",o:["Complete bed rest to promote healing","Progressive mobilization as ordered — dangling, standing, then walking","Vigorous active ROM of the hip joint","Unrestricted ambulation without assistance"],c:[1],e:"Progressive mobilization (dangling → standing → walking) is the standard approach after hip replacement to prevent immobility complications while protecting the surgical site. Complete bed rest increases complications. Vigorous ROM could damage the new joint. Unrestricted ambulation is unsafe this early.",a:"B) Progressive mobilization as ordered — dangling, standing, then walking",r:"Prioritizing — Post-Op Mobility"},
{id:65,s:"CR",t:"mc",q:"Which crutch gait should the nurse teach a patient who can bear weight on BOTH legs and needs the MOST stable gait?",o:["2-point gait","3-point gait","4-point gait","Swing-through gait"],c:[2],e:"The 4-point gait is the most stable crutch gait because 3 points of contact are always on the floor. It requires weight bearing on both legs. The 3-point gait is for non-weight-bearing. The 2-point gait is faster but less stable. Swing-through is for paraplegia patients.",a:"C) 4-point gait",r:"Crutch Gaits"},
{id:66,s:"CR",t:"mc",q:"A patient with a fractured left tibia is non-weight-bearing on the left leg. Which gait pattern should the nurse prioritize teaching?",o:["4-point gait","2-point gait","3-point gait","Swing-through gait"],c:[2],e:"The 3-point gait is used when the patient cannot bear weight on one leg — both crutches advance with the affected leg, and all weight is borne on the unaffected leg. The 4-point and 2-point gaits require weight bearing on both legs. Swing-through is for paraplegia.",a:"C) 3-point gait",r:"Crutch Gaits"},
{id:67,s:"MO",t:"mc",q:"The nurse is delegating care for immobile patients. Which task is MOST appropriate to delegate to a UAP (unlicensed assistive personnel)?",o:["Assessing skin integrity on bony prominences","Teaching the patient about pressure ulcer prevention","Repositioning the patient every 2 hours per the care plan","Developing the patient's mobility plan"],c:[2],e:"Repositioning per an established care plan is a routine task that can be safely delegated to a UAP. Assessment, teaching, and care planning are nursing responsibilities that require professional judgment and cannot be delegated.",a:"C) Repositioning the patient every 2 hours per the care plan",r:"Prioritizing — Delegation"},
{id:68,s:"MO",t:"sata",q:"Which interventions should the nurse prioritize to prevent complications of immobility? Select all that apply.",o:["Repositioning every 2 hours","Encouraging fluids to prevent urinary stasis","Applying SCDs or antiembolic stockings","Performing ROM exercises","All of the above"],c:[4],e:"ALL of these interventions are priorities for immobile patients: repositioning prevents pressure ulcers, fluids prevent urinary stasis, SCDs/stockings prevent DVT, and ROM exercises prevent contractures and muscle atrophy. A comprehensive approach addresses all body systems.",a:"E) All of the above",r:"Prioritizing — Immobility Prevention"},
{id:69,s:"CR",t:"mc",q:"A nurse is teaching crutch walking. Which instruction has the HIGHEST priority?",o:["'Move at a comfortable pace'","'Never rest your weight on the underarm pads — bear weight on your hands'","'Wear comfortable shoes'","'Take breaks as needed'"],c:[1],e:"The highest priority instruction is preventing axillary nerve damage — weight must be borne on the hands through the hand grips, NOT on the underarm pads. 'No weight on pits!' Comfortable shoes, pacing, and breaks are important but secondary to preventing nerve injury.",a:"B) 'Never rest your weight on the underarm pads — bear weight on your hands'",r:"Prioritizing — Crutch Teaching"},
{id:70,s:"MO",t:"order",q:"Place the steps of progressive mobilization in the correct order.",o:["Dangle legs at the bedside","Sit up in bed","Stand at the bedside with assistance","Ambulate with assistance"],c:[1,0,2,3],e:"Progressive mobilization follows a stepwise approach: first sit up in bed → dangle legs at the bedside (to assess for orthostatic hypotension) → stand at bedside with assistance → ambulate with assistance. Each step is assessed before progressing to prevent falls and complications.",a:"Sit up → Dangle → Stand → Ambulate",r:"Progressive Mobilization"},
{id:71,s:"CR",t:"order",q:"Place the steps for going UPSTAIRS with crutches in the correct order.",o:["Advance the strong (unaffected) leg up to the step","Bring the crutches and affected leg up to the same step","Assess the stairway for safety","Repeat until at the top"],c:[2,0,1,3],e:"Going upstairs: 'Up with the good.' First assess safety, then lead with the strong leg, followed by crutches and the affected leg together. Remember: the strong leg goes up first because it does the work of lifting the body. Repeat for each step.",a:"Assess → Strong leg up → Crutches + affected leg up → Repeat",r:"Crutch Stair Technique"},
{id:72,s:"CR",t:"order",q:"Place the steps for going DOWNSTAIRS with crutches in the correct order.",o:["Lower the affected leg and crutches to the step below","Assess the stairway for safety","Bring the strong leg down to the same step","Repeat until at the bottom"],c:[1,0,2,3],e:"Going downstairs: 'Down with the bad.' First assess safety, then the crutches and affected leg go down first, followed by the strong leg. The strong leg stays on the higher step to control the descent. Repeat for each step.",a:"Assess → Crutches + affected leg down → Strong leg down → Repeat",r:"Crutch Stair Technique"},
{id:73,s:"MO",t:"mc",q:"A nurse must prioritize care for two patients: Patient A needs repositioning (last turned 2.5 hours ago) and Patient B needs their scheduled incentive spirometry. Which should be done FIRST?",o:["Patient A — repositioning is overdue","Patient B — respiratory care always comes first","Both can wait another hour","Ask the UAP to decide"],c:[0],e:"Patient A is overdue for repositioning (past the 2-hour minimum), increasing pressure ulcer risk. The incentive spirometer is scheduled but the patient is not in acute respiratory distress. Repositioning the overdue patient takes priority. Neither should wait, and the UAP should not make prioritization decisions.",a:"A) Patient A — repositioning is overdue",r:"Prioritizing — Time-Sensitive Care"},
{id:74,s:"CR",t:"mc",q:"The 2-point crutch gait mimics which pattern?",o:["Hopping on one foot","Normal walking — opposite arm and leg move together","Swinging through the crutches","Walking with both crutches then both feet"],c:[1],e:"The 2-point gait mimics normal walking: the right crutch moves with the left leg, and the left crutch moves with the right leg (opposite arm-leg pattern). It requires partial weight bearing on both feet. The other descriptions match swing-through, 3-point, or no recognized gait.",a:"B) Normal walking — opposite arm and leg move together",r:"Crutch Gaits"},
{id:75,s:"CR",t:"mc",q:"Which crutch gait is appropriate for a patient with paraplegia who has leg braces?",o:["4-point gait","3-point gait","2-point gait","Swing-through gait"],c:[3],e:"The swing-through gait is used by patients with paraplegia who wear bilateral leg braces — they place both crutches forward and swing their body through and past the crutches. The 4-point, 3-point, and 2-point gaits require varying degrees of leg weight bearing that paraplegic patients cannot perform.",a:"D) Swing-through gait",r:"Crutch Gaits"},
{id:76,s:"MO",t:"mc",q:"A nurse is planning ROM exercises for a patient with a right arm cast. Which type of ROM is appropriate for the casted extremity?",o:["Active ROM of the right arm","Passive ROM of the joints above and below the cast","No ROM should be performed on the casted side","Resistive ROM of the right elbow"],c:[1],e:"For a casted extremity, passive ROM should be performed on the joints above and below the cast (such as fingers and shoulder) to maintain mobility without disrupting the fracture site. Active and resistive ROM of immobilized joints is contraindicated. Doing nothing leads to stiffness and complications.",a:"B) Passive ROM of the joints above and below the cast",r:"Prioritizing — ROM Exercises"},
{id:77,s:"MO",t:"sata",q:"Which are risk factors for pressure ulcer development? Select all that apply.",o:["Immobility","Malnutrition","Moisture (incontinence)","Decreased sensation","Obesity and very thin body habitus"],c:[0,1,2,3,4],e:"ALL of these are pressure ulcer risk factors: immobility prevents pressure relief, malnutrition impairs tissue integrity, moisture macerates skin, decreased sensation prevents the person from feeling pain that signals tissue damage, and both obesity and thinness affect pressure distribution.",a:"A, B, C, D, E) All options",r:"Prioritizing — Pressure Ulcer Risk",},
{id:78,s:"MO",t:"mc",q:"A nurse is prioritizing morning care. Which patient should receive ambulation assistance FIRST?",o:["A patient 1 day post-op who has an order to ambulate TID","A patient 3 days post-op who is independently ambulatory","A patient who is on strict bed rest","A patient who ambulates independently with a cane"],c:[0],e:"The 1-day post-op patient with ambulation orders needs priority assistance because early post-op mobilization prevents DVT, atelectasis, and ileus. The independently ambulatory patients can manage on their own, and the bed rest patient cannot ambulate.",a:"A) A patient 1 day post-op who has an order to ambulate TID",r:"Prioritizing — Post-Op Ambulation"},
{id:79,s:"MO",t:"mc",q:"Which type of exercise maintains joint mobility without muscle contraction?",o:["Isometric exercises","Isotonic exercises","Passive ROM exercises","Resistive exercises"],c:[2],e:"Passive ROM exercises are performed by someone else moving the patient's joints through their full range — no active muscle contraction occurs. Isometric exercises involve muscle contraction without joint movement. Isotonic and resistive exercises both require active muscle contraction.",a:"C) Passive ROM exercises",r:"Prioritizing — Exercise Types"},
{id:80,s:"MO",t:"mc",q:"When performing body mechanics during patient lifting, the nurse should:",o:["Bend at the waist to reach the patient","Use the large muscles of the legs to lift","Keep feet close together for stability","Twist at the trunk to turn"],c:[1],e:"Proper body mechanics require using the large leg muscles (quadriceps, glutes) to lift — not bending at the waist (strains back), keeping feet close together (decreases stability; wide base is correct), or twisting (causes injury; turn whole body instead).",a:"B) Use the large muscles of the legs to lift",r:"Body Mechanics"},
{id:81,s:"CR",t:"mc",q:"When fitting crutches, the crutch tip should be placed:",o:["Directly beside the patient's feet","6 inches (15 cm) in front and to the side of the feet (tripod position)","12 inches behind the patient","Touching the patient's toes"],c:[1],e:"The tripod position places crutch tips 6 inches (15 cm) in front and 6 inches to the side — this provides the most stable base of support. Directly beside the feet, behind the patient, or touching the toes would all create unstable or dangerous positions.",a:"B) 6 inches (15 cm) in front and to the side of the feet (tripod position)",r:"Crutch Fitting"},
{id:82,s:"CR",t:"mc",q:"The nurse is teaching a patient to use a cane. Which statement by the patient indicates correct understanding?",o:["'I will hold the cane on the same side as my weak leg'","'I will hold the cane on the opposite side of my weak leg and advance it with my weak leg'","'I will keep the cane behind me as I walk'","'I will use the cane only when I feel dizzy'"],c:[1],e:"Correct cane technique: hold the cane on the OPPOSITE side of the weak leg and advance it simultaneously with the weak leg, then step with the strong leg. Remember: 'Cane on the GOOD side, step with the BAD side.' The other options describe incorrect or unsafe technique.",a:"B) 'I will hold the cane on the opposite side of my weak leg and advance it with my weak leg'",r:"Cane Technique"},
{id:83,s:"CR",t:"order",q:"Place the steps for using a walker in the correct order.",o:["Step with the weak/affected leg into the walker","Move the walker forward 6-12 inches","Step with the strong leg","Stand upright in the middle of the walker"],c:[3,1,0,2],e:"Correct walker sequence: Stand upright in the middle → move the walker forward → step with the weak leg first (into the support of the walker) → then step with the strong leg. This ensures the walker provides support during the most vulnerable phase of gait.",a:"Stand → Walker forward → Weak leg → Strong leg",r:"Walker Technique"},
{id:84,s:"MO",t:"sata",q:"Which interventions prevent DVT in an immobilized patient? Select all that apply.",o:["Antiembolic (TED) stockings","Sequential compression devices (SCDs)","Early ambulation","Adequate hydration","Incentive spirometry"],c:[0,1,2,3],e:"TED stockings, SCDs, early ambulation, and adequate hydration all help prevent DVT by promoting venous return and preventing blood stasis. Incentive spirometry prevents respiratory complications (atelectasis), not DVT.",a:"A, B, C, D) TED stockings, SCDs, Early ambulation, Adequate hydration",r:"Prioritizing — DVT Prevention"},
{id:85,s:"MO",t:"mc",q:"Isometric exercises involve:",o:["Moving the joint through its full range of motion","Contracting muscles without moving the joint","Using weights to strengthen muscles","Having someone else move the patient's limbs"],c:[1],e:"Isometric exercises involve muscle contraction without joint movement — like pushing against a wall. Moving joints through ROM describes isotonic or ROM exercises. Using weights is resistive exercise. Having someone else move limbs is passive ROM.",a:"B) Contracting muscles without moving the joint",r:"Exercise Types"},
{id:86,s:"MO",t:"mc",q:"A patient asks why they need to change positions so often. The BEST nursing response is:",o:["'It's hospital policy and we have to follow the rules'","'Changing positions prevents pressure on your skin, helps your lungs expand, and keeps blood flowing properly'","'Your doctor ordered it, so we need to do it'","'It's just to keep you comfortable'"],c:[1],e:"The best response educates the patient about the therapeutic reasons: preventing pressure ulcers (skin), atelectasis (lungs), and DVT (circulation). Simply citing policy or physician orders doesn't promote understanding. Comfort alone doesn't capture the medical necessity.",a:"B) 'Changing positions prevents pressure on your skin, helps your lungs expand, and keeps blood flowing properly'",r:"Patient Education"},
{id:87,s:"MO",t:"mc",q:"Which position places the immobilized patient at GREATEST risk for aspiration?",o:["Semi-Fowler's position","Supine (flat on back) position","Side-lying position","High-Fowler's position"],c:[1],e:"The supine (flat) position places the patient at greatest aspiration risk because gravity cannot help keep stomach contents from entering the airway. Semi-Fowler's and High-Fowler's elevate the head, reducing risk. Side-lying allows secretions to drain from the mouth.",a:"B) Supine (flat on back) position",r:"Prioritizing — Positioning"},
{id:88,s:"MO",t:"fib",q:"The nurse should reposition an immobilized patient at least every ____ hours to prevent pressure ulcers.",o:[],c:["2"],e:"The standard of care for pressure ulcer prevention is repositioning at least every 2 hours. This timeframe is based on research showing that tissue damage can begin after approximately 2 hours of unrelieved pressure on bony prominences.",a:"2",r:"Immobility Interventions"},
{id:89,s:"CR",t:"fib",q:"When fitting crutches, there should be ____ to ____ finger widths between the axilla and the crutch pad.",o:[],c:["2","3"],e:"Proper crutch fitting requires 2-3 finger widths (approximately 1-2 inches or 2.5-5 cm) between the axilla and the top of the crutch pad. This gap ensures the patient bears weight on their hands, not their axillae, preventing brachial plexus nerve damage.",a:"2 to 3",r:"Crutch Fitting"},
{id:90,s:"MO",t:"sata",q:"Which postural misalignments can the nurse identify during assessment? Select all that apply.",o:["Lordosis","Kyphosis","Scoliosis","Flat back","Sway back"],c:[0,1,2,3,4],e:"All five are postural misalignments a nurse should assess: Lordosis (exaggerated lumbar curve), Kyphosis (exaggerated thoracic curve), Scoliosis (lateral spine curvature), Flat back (loss of lumbar curve), and Sway back (forward hip displacement). Each affects mobility and body mechanics differently.",a:"A, B, C, D, E) All options",r:"Postural Assessment"},

// ===== COMPLEX IMPLEMENTATION (Q91-120) =====
{id:91,s:"MO",t:"mc",q:"A patient with left-sided weakness after a stroke is learning to use a cane. The nurse observes the patient holding the cane in the left hand. The nurse should:",o:["Praise the patient for using the cane","Move the cane to the patient's RIGHT hand and explain it provides better support","Tell the patient to stop using the cane entirely","Let the patient continue since they feel comfortable"],c:[1],e:"The cane must be held on the OPPOSITE side of the weak leg — so for left-sided weakness, the cane goes in the RIGHT hand. This shifts the center of gravity and provides a wider base of support. Using it on the weak side does not provide proper biomechanical advantage. Remember: 'Cane on the GOOD side.'",a:"B) Move the cane to the patient's RIGHT hand and explain it provides better support",r:"Cane Implementation"},
{id:92,s:"CR",t:"mc",q:"A nurse is teaching a patient with a right fractured femur who is non-weight-bearing. When going upstairs, the patient should:",o:["Lead with the right (affected) leg","Lead with the left (unaffected) leg, then bring crutches and right leg up","Lead with both crutches, then bring both legs up","Avoid stairs entirely until fully healed"],c:[1],e:"Going upstairs: 'Up with the good.' The strong (left/unaffected) leg leads going up, then crutches and affected leg follow. Leading with the affected leg is dangerous. Leading with crutches alone is incorrect technique. Patients can use stairs with proper training.",a:"B) Lead with the left (unaffected) leg, then bring crutches and right leg up",r:"Crutch Stair Technique"},
{id:93,s:"MO",t:"mc",q:"A nurse is implementing a progressive exercise program for a patient who has been on bed rest for 2 weeks. The patient becomes dizzy when sitting up. The BEST action is:",o:["Lay the patient back down and cancel all further mobilization attempts","Have the patient sit at the bedside and dangle their legs until the dizziness passes, then reassess","Stand the patient up quickly to overcome the dizziness","Administer an antiemetic and continue standing"],c:[1],e:"Dangling allows gradual cardiovascular adjustment and is the standard response to orthostatic symptoms during progressive mobilization. Canceling mobilization entirely delays recovery. Standing quickly worsens orthostatic hypotension. An antiemetic treats nausea, not the underlying blood pressure issue.",a:"B) Have the patient sit at the bedside and dangle their legs until the dizziness passes, then reassess",r:"Progressive Mobilization"},
{id:94,s:"CR",t:"mc",q:"A patient asks: 'Why can't I just lean on the top of the crutches under my arms? It's easier.' The BEST response is:",o:["'Go ahead, whatever is most comfortable'","'Leaning on the axillary pads can compress nerves and blood vessels, causing numbness or permanent damage — always bear weight on your hands'","'The physical therapist will explain that to you'","'It doesn't really matter as long as you're moving'"],c:[1],e:"Weight on the axillae compresses the brachial plexus nerves and blood vessels, potentially causing 'crutch palsy' — numbness, tingling, or even permanent nerve damage. Remember: 'No weight on pits!' The nurse should educate directly rather than deferring or dismissing the concern.",a:"B) 'Leaning on the axillary pads can compress nerves and blood vessels, causing numbness or permanent damage — always bear weight on your hands'",r:"Crutch Patient Education"},
{id:95,s:"MO",t:"mc",q:"A nurse is implementing turning and positioning for a patient with a Stage 2 pressure ulcer on the sacrum. The MOST appropriate intervention is:",o:["Position the patient supine with extra padding on the sacrum","Avoid positioning the patient on the sacrum and use 30-degree lateral positions","Turn the patient onto the sacrum for only 30 minutes at a time","Apply a heating pad to the sacrum to promote circulation"],c:[1],e:"With a sacral pressure ulcer, the nurse must avoid positioning the patient on the affected area. The 30-degree lateral position offloads the sacrum while preventing pressure on the trochanters. Extra padding on the sacrum still allows pressure. Brief supine positioning continues injury. Heat can increase tissue damage.",a:"B) Avoid positioning the patient on the sacrum and use 30-degree lateral positions",r:"Pressure Ulcer Management"},
{id:96,s:"MO",t:"sata",q:"A nurse is implementing a care plan for an immobile patient. Which nursing interventions address musculoskeletal complications? Select all that apply.",o:["Active or passive ROM exercises","Isometric exercises (quadriceps sets, gluteal sets)","Progressive ambulation as tolerated","Use of a trapeze for self-repositioning","Applying antiembolic stockings"],c:[0,1,2,3],e:"ROM exercises, isometric exercises, progressive ambulation, and trapeze use all address musculoskeletal complications (contractures, atrophy, weakness). Antiembolic stockings address cardiovascular complications (DVT prevention), not musculoskeletal.",a:"A, B, C, D) ROM, isometric exercises, progressive ambulation, trapeze",r:"Musculoskeletal Interventions"},
{id:97,s:"CR",t:"mc",q:"A nurse is teaching a patient the 4-point gait. The correct sequence is:",o:["Right crutch → left foot → left crutch → right foot","Both crutches → both feet → repeat","Right crutch → right foot → left crutch → left foot","Both crutches → swing body through"],c:[0],e:"The 4-point gait alternates: right crutch → left foot → left crutch → right foot (opposite crutch-foot pattern). Three points are always on the floor, making it the most stable gait. Both crutches then both feet describes no standard gait. Same-side crutch-foot is incorrect. Swing-through is a different gait entirely.",a:"A) Right crutch → left foot → left crutch → right foot",r:"4-Point Gait Implementation"},
{id:98,s:"MO",t:"mc",q:"A nurse is teaching body mechanics to nursing students. Which statement requires correction?",o:["'Keep the object close to your body when lifting'","'Bend at the knees and hips, not the waist'","'Twist at your waist to change direction while holding a patient'","'Maintain a wide base of support'"],c:[2],e:"Twisting at the waist while lifting or holding a patient is INCORRECT and can cause serious back injury. The nurse should pivot by turning the entire body as a unit. Keeping objects close, bending at knees/hips, and maintaining a wide base of support are all correct body mechanics principles.",a:"C) 'Twist at your waist to change direction while holding a patient'",r:"Body Mechanics"},
{id:99,s:"MO",t:"mc",q:"A patient who has been immobile for 3 days develops a footdrop. Which device should the nurse implement to correct this?",o:["Trochanter roll","Hand roll","Footboard or ankle-foot orthosis","Abduction pillow"],c:[2],e:"Footdrop (plantar flexion contracture) is prevented and managed with a footboard or ankle-foot orthosis that keeps the foot in dorsiflexion. A trochanter roll prevents external hip rotation. A hand roll prevents finger contractures. An abduction pillow keeps hips abducted after hip surgery.",a:"C) Footboard or ankle-foot orthosis",r:"Positioning Devices"},
{id:100,s:"MO",t:"order",q:"Place the steps for safely transferring a patient from bed to wheelchair in the correct order.",o:["Lock the wheelchair brakes and position the chair at a 45-degree angle to the bed","Assist the patient to stand and pivot toward the wheelchair","Have the patient sit on the edge of the bed with feet flat on the floor","Lower the patient into the wheelchair"],c:[0,2,1,3],e:"Safe bed-to-wheelchair transfer: First secure the wheelchair (lock brakes, position at 45°) → patient sits at edge with feet flat (assesses balance) → assist to stand and pivot → lower into chair. Securing equipment first prevents it from moving during transfer.",a:"Lock wheelchair → Sit at edge → Stand and pivot → Lower into chair",r:"Transfer Technique"},
{id:101,s:"CR",t:"mc",q:"A patient with bilateral lower extremity weakness asks which assistive device would be BEST for them. The nurse recommends:",o:["A single-point cane","Forearm crutches only","A standard walker","A single crutch on the stronger side"],c:[2],e:"A walker provides the most support and stability for patients with bilateral lower extremity weakness — it offers a wide, stable base with four points of contact. A single-point cane provides minimal support. Forearm crutches require more upper body coordination. A single crutch is inadequate for bilateral weakness.",a:"C) A standard walker",r:"Assistive Device Selection"},
{id:102,s:"MO",t:"mc",q:"A nurse is implementing care for a patient with kyphosis. Which intervention is MOST important?",o:["Encourage prone positioning to straighten the spine","Assess respiratory status because thoracic curvature can restrict lung expansion","Apply a back brace without a physician's order","Teach the patient vigorous stretching exercises"],c:[1],e:"Kyphosis (exaggerated thoracic curvature) can restrict lung expansion by reducing thoracic cage volume, making respiratory assessment a priority. Prone positioning may be uncomfortable and is not standard treatment. Bracing requires an order. Vigorous stretching could worsen the condition.",a:"B) Assess respiratory status because thoracic curvature can restrict lung expansion",r:"Postural Misalignment Care"},
{id:103,s:"MO",t:"sata",q:"Which complications should the nurse monitor for in a patient who has been immobile for 1 week? Select all that apply.",o:["Atelectasis","Deep vein thrombosis","Pressure ulcers","Contractures","Constipation"],c:[0,1,2,3,4],e:"After 1 week of immobility, the patient is at risk for ALL listed complications: atelectasis (shallow breathing), DVT (venous stasis), pressure ulcers (sustained pressure), contractures (lack of joint movement), and constipation (decreased peristalsis). Immobility affects every body system.",a:"A, B, C, D, E) All options",r:"Immobility Monitoring"},
{id:104,s:"CR",t:"mc",q:"A nurse evaluates a patient's understanding of the 3-point gait. Which patient statement indicates correct understanding?",o:["'I advance my good leg and one crutch, then bring my bad leg and other crutch forward'","'I advance both crutches and my bad leg together, then step with my good leg'","'I move all four points at the same time'","'I move one crutch, then one foot, then the other crutch, then the other foot'"],c:[1],e:"The 3-point gait: both crutches and the affected (non-weight-bearing) leg advance together, then the unaffected leg steps through. Option A describes 2-point gait. Option C is unsafe. Option D describes 4-point gait. The 3-point gait keeps all weight off the injured leg.",a:"B) 'I advance both crutches and my bad leg together, then step with my good leg'",r:"3-Point Gait Understanding"},
{id:105,s:"MO",t:"mc",q:"A nurse is positioning an immobile patient. Which bony prominence is at HIGHEST risk for pressure ulcer development in the supine position?",o:["Greater trochanter","Sacrum","Lateral malleolus","Ischial tuberosity"],c:[1],e:"In the supine position, the sacrum bears the most pressure and is the most common site for pressure ulcers. The greater trochanter is at risk in side-lying position. The lateral malleolus is at risk in side-lying. The ischial tuberosities are at risk in sitting position.",a:"B) Sacrum",r:"Pressure Ulcer Prevention"},
{id:106,s:"MO",t:"mc",q:"A nurse is teaching a UAP about proper body mechanics. Which observation indicates the UAP needs additional instruction?",o:["The UAP bends the knees when picking up equipment from the floor","The UAP holds a supply box close to the body while carrying it","The UAP uses a wide stance when assisting a patient to stand","The UAP reaches overhead and twists to place items on a high shelf"],c:[3],e:"Reaching overhead while twisting combines two dangerous body mechanics errors that significantly increase injury risk. Bending at the knees, holding objects close, and using a wide stance are all correct body mechanics techniques.",a:"D) The UAP reaches overhead and twists to place items on a high shelf",r:"Body Mechanics Teaching"},
{id:107,s:"CR",t:"mc",q:"A patient with right-sided weakness is using a cane to go up stairs. The nurse instructs the patient to:",o:["Lead with the cane and right (weak) leg going up","Lead with the left (strong) leg going up, then bring the cane and weak leg up","Lead with the cane only, then bring both feet up together","Avoid stairs completely when using a cane"],c:[1],e:"Going upstairs with a cane: 'Up with the good' — the strong leg leads, then the cane and weak leg follow. Leading with the weak leg going up is unsafe as it lacks the strength to lift the body. Patients can learn safe stair technique with a cane.",a:"B) Lead with the left (strong) leg going up, then bring the cane and weak leg up",r:"Cane Stair Technique"},
{id:108,s:"MO",t:"tf",q:"True or False: A trochanter roll is used to prevent external rotation of the hip.",o:["True","False"],c:[0],e:"This is TRUE. A trochanter roll is placed along the outer thigh from the iliac crest to mid-thigh to prevent external hip rotation in supine patients. Without it, gravity causes the hip to externally rotate, which can lead to contracture and gait problems.",a:"A) True",r:"Positioning Devices"},
{id:109,s:"MO",t:"tf",q:"True or False: When lifting a heavy object, the nurse should maintain a wide base of support and keep the object close to the body.",o:["True","False"],c:[0],e:"This is TRUE. A wide base of support (feet shoulder-width apart) increases stability, and keeping the object close to the body reduces the lever arm, decreasing strain on the back muscles. These are fundamental principles of proper body mechanics.",a:"A) True",r:"Body Mechanics"},
{id:110,s:"CR",t:"tf",q:"True or False: In the 4-point gait, the patient must be able to bear weight on both legs.",o:["True","False"],c:[0],e:"This is TRUE. The 4-point gait requires weight bearing on BOTH legs because each leg alternately supports the body as the opposite crutch advances. Patients who cannot bear weight on one leg should use the 3-point gait instead.",a:"A) True",r:"Crutch Gaits"},
{id:111,s:"MO",t:"mc",q:"A nurse is caring for a patient in skeletal traction. Which is the MOST important nursing intervention to prevent respiratory complications?",o:["Position the patient flat to maintain traction alignment","Encourage deep breathing and coughing exercises every 1-2 hours","Limit fluid intake to reduce pulmonary edema","Discourage movement to prevent pain"],c:[1],e:"Deep breathing and coughing every 1-2 hours prevents atelectasis and pneumonia in traction patients. Flat positioning may be required for traction but doesn't prevent respiratory complications. Limiting fluids causes dehydration. Discouraging movement worsens immobility complications.",a:"B) Encourage deep breathing and coughing exercises every 1-2 hours",r:"Traction Respiratory Care"},
{id:112,s:"MO",t:"mc",q:"A patient with a newly applied long leg cast reports increasing pain and tingling in the toes. The nurse should FIRST:",o:["Administer pain medication as ordered","Elevate the extremity and perform a neurovascular check","Reassure the patient that this is normal after casting","Loosen the cast independently"],c:[1],e:"Increasing pain and tingling may indicate compartment syndrome or circulatory compromise — the nurse should elevate the extremity and perform a neurovascular check (5 P's: Pain, Pallor, Pulselessness, Paresthesia, Paralysis). Pain medication may mask symptoms. This is NOT normal. Only the provider can modify the cast.",a:"B) Elevate the extremity and perform a neurovascular check",r:"Cast Care — Neurovascular"},
{id:113,s:"CR",t:"sata",q:"Which instructions should the nurse include when teaching a patient about crutch safety? Select all that apply.",o:["Bear weight on your hands, not your axillae","Wear sturdy, non-skid shoes","Remove throw rugs and obstacles from walkways at home","Look at your feet while walking for safety","Maintain the tripod position when standing still"],c:[0,1,2,4],e:"Safe crutch use includes: bearing weight on hands (prevents nerve damage), non-skid shoes (prevents falls), removing home hazards, and maintaining tripod position (6 inches in front and to the side). Looking at feet while walking actually increases fall risk — patients should look ahead.",a:"A, B, C, E) Bear weight on hands, Non-skid shoes, Remove hazards, Tripod position",r:"Crutch Safety Teaching"},
{id:114,s:"MO",t:"mc",q:"A nurse is implementing fall prevention for an immobilized patient who is beginning to ambulate. Which intervention is MOST important?",o:["Keep the bed in the lowest position with the call light within reach","Apply physical restraints during ambulation","Allow the patient to ambulate independently to promote confidence","Dim the room lights to reduce stimulation"],c:[0],e:"Keeping the bed low and call light within reach are essential fall prevention measures. Restraints are a last resort and are not used during ambulation. Independent ambulation without assessment is unsafe for newly mobilizing patients. Dim lighting increases fall risk.",a:"A) Keep the bed in the lowest position with the call light within reach",r:"Fall Prevention"},
{id:115,s:"MO",t:"sata",q:"The nurse is implementing interventions for a patient at risk for contractures. Which are appropriate? Select all that apply.",o:["Perform ROM exercises at least twice daily","Maintain proper body alignment with supportive devices","Use a footboard to prevent footdrop","Apply splints as ordered to maintain functional position","Keep the patient in one position to prevent pain"],c:[0,1,2,3],e:"ROM exercises, proper alignment, footboards, and splints all prevent contractures by maintaining joint mobility and positioning. Keeping the patient in one position is the opposite of what should be done — it promotes contractures. Movement and position changes are essential.",a:"A, B, C, D) ROM, alignment, footboard, splints",r:"Contracture Prevention"},
{id:116,s:"CR",t:"mc",q:"A patient who had a left total knee replacement is progressing from a walker to a cane. Which gait pattern should the nurse teach for the cane?",o:["Hold cane in the left hand, advance with the left leg","Hold cane in the right hand, advance the cane and left leg together, then step with the right leg","Hold cane in either hand, whichever feels comfortable","Use the cane behind the body for balance"],c:[1],e:"For a left knee replacement: hold the cane in the RIGHT hand (opposite the affected side), advance the cane and left (weak) leg together, then step with the right (strong) leg. 'Cane on the GOOD side, step with the BAD side.' Comfort preference is incorrect — biomechanics dictate hand placement.",a:"B) Hold cane in the right hand, advance the cane and left leg together, then step with the right leg",r:"Cane Technique Implementation"},
{id:117,s:"MO",t:"mc",q:"A patient immobilized for 10 days develops a serum calcium level of 11.8 mg/dL. The nurse recognizes this as:",o:["Expected and within normal limits","Hypocalcemia from immobility","Hypercalcemia from calcium being released from unstressed bones","An unrelated laboratory finding"],c:[2],e:"Normal serum calcium is 8.5-10.5 mg/dL. A level of 11.8 mg/dL indicates hypercalcemia, which occurs in immobility because bones that are not bearing weight release calcium into the bloodstream. This is not normal, not hypocalcemia, and is directly related to immobility.",a:"C) Hypercalcemia from calcium being released from unstressed bones",r:"Metabolic Complications"},
{id:118,s:"MO",t:"order",q:"Place the nurse's actions in correct priority order when a patient falls during ambulation.",o:["Assess the patient for injuries","Gently lower the patient to the floor if they are falling","Notify the healthcare provider","Complete an incident report"],c:[1,0,2,3],e:"When a patient falls: First, safely lower them to the floor to prevent further injury → assess for injuries (head, spine, extremities) → notify the provider with findings → complete the incident report for documentation. Safety first, then assessment, notification, and documentation.",a:"Lower to floor → Assess injuries → Notify provider → Incident report",r:"Fall Response"},
{id:119,s:"MO",t:"fib",q:"The tripod position for crutch standing places the crutch tips ____ inches in front and to the side of the feet.",o:[],c:["6"],e:"The tripod position places crutch tips 6 inches (15 cm) in front and 6 inches to the side of each foot, creating a triangular base of support. This position provides maximum stability when standing with crutches.",a:"6",r:"Crutch Positioning"},
{id:120,s:"CR",t:"mc",q:"A nursing student asks why patients with paraplegia use the swing-through gait instead of a 4-point gait. The BEST response is:",o:["'The swing-through gait is easier to learn'","'Patients with paraplegia cannot bear weight on their legs, so they use leg braces and swing their body through the crutches'","'The 4-point gait is too slow for paraplegic patients'","'There is no difference between the two gaits'"],c:[1],e:"Patients with paraplegia have no voluntary leg movement, so they cannot perform gaits requiring active leg movement (4-point, 3-point, 2-point). With bilateral leg braces for stability, they place both crutches forward and swing their entire body through and past the crutches. Speed and ease of learning are not the determining factors.",a:"B) 'Patients with paraplegia cannot bear weight on their legs, so they use leg braces and swing their body through the crutches'",r:"Swing-Through Gait"}
];
export const QUESTIONS_MOBILITY = R.map(q => ({...q, section: S[q.s], type: q.t, options: q.o || [], correct: q.c, explanation: q.e, correctAnswer: q.a, ref: q.r, stem: q.q}));
export const SECTIONS_MOBILITY = Object.values(S);
